### File 1: ~/.pi/agent/extensions/latex/detect.ts

Port the Python detection scripts to TypeScript. This file exports detection functions for TeX Live and Tectonic.

```typescript
import * as fs from "node:fs";
import * as path from "node:path";
import { execFile } from "node:child_process";

export interface TexLiveCommands {
  latexmk: { path: string | null; version: string | null };
  pdflatex: { path: string | null; version: string | null };
  xelatex: { path: string | null; version: string | null };
  lualatex: { path: string | null; version: string | null };
  biber: { path: string | null; version: string | null };
  kpsewhich: { path: string | null; version: string | null };
}

export interface TexLiveDetection {
  status: "missing" | "existing-partial" | "existing-usable";
  reason: string;
  activeBinDir: string | null;
  texmfroot: string | null;
  commands: TexLiveCommands;
  missingRequired: string[];
  missingRecommended: string[];
  knownTexBinDirs: string[];
  searchPath: string;
}

export interface TectonicDetection {
  status: "available" | "missing";
  reason: string;
  path: string | null;
  source: string | null;
  version: string | null;
}

const REQUIRED_TOOLS = ["latexmk", "pdflatex", "kpsewhich"] as const;
const RECOMMENDED_TOOLS = ["xelatex", "lualatex", "biber"] as const;
const ALL_TOOLS = [...REQUIRED_TOOLS, ...RECOMMENDED_TOOLS] as const;

function execTool(args: string[], envPath: string, timeout = 10_000): Promise<{ code: number; stdout: string }> {
  return new Promise((resolve) => {
    const env = { ...process.env, PATH: envPath };
    const child = execFile(args[0], args.slice(1), { env, timeout }, (error, stdout) => {
      const code = error?.code ?? 0;
      resolve({ code, stdout: stdout?.trim() ?? "" });
    });
    if (!child || !child.stdout) return;
  });
}

function which(tool: string, searchPath: string): string | null {
  const paths = searchPath.split(path.delimiter);
  for (const dir of paths) {
    const full = path.join(dir, tool);
    try {
      fs.accessSync(full, fs.constants.X_OK);
      return full;
    } catch {
      // try next
    }
  }
  return null;
}

function discoverKnownBinDirs(): string[] {
  const candidates: string[] = [];
  const home = require("node:os").homedir();

  // MacTeX symlink
  try { if (fs.statSync("/Library/TeX/texbin").isDirectory()) candidates.push("/Library/TeX/texbin"); } catch {}

  // /usr/local/texlive/*/bin/*
  try {
    const dirs = fs.readdirSync("/usr/local/texlive");
    for (const year of dirs.sort().reverse()) {
      const binDir = path.join("/usr/local/texlive", year, "bin");
      try {
        const arches = fs.readdirSync(binDir);
        for (const arch of arches.sort().reverse()) {
          candidates.push(path.join(binDir, arch));
        }
      } catch {}
    }
  } catch {}

  // user's TinyTeX at ~/Documents/Resume/texlive/bin/universal-darwin
  const tinytex = path.join(home, "Documents", "Resume", "texlive", "bin", "universal-darwin");
  try { if (fs.statSync(tinytex).isDirectory()) candidates.push(tinytex); } catch {}

  // Deduplicate and check existence
  const seen = new Set<string>();
  const existing: string[] = [];
  for (const c of candidates) {
    const normalized = path.normalize(c);
    if (!seen.has(normalized) && existsDir(normalized)) {
      seen.add(normalized);
      existing.push(normalized);
    }
  }
  return existing;
}

function existsDir(p: string): boolean {
  try { return fs.statSync(p).isDirectory(); } catch { return false; }
}

function buildSearchPath(extraPaths?: string[]): string {
  const paths = [...(extraPaths ?? []), ...discoverKnownBinDirs()];
  const currentPath = process.env.PATH ?? "";
  if (currentPath) paths.push(...currentPath.split(path.delimiter));

  const seen = new Set<string>();
  return paths
    .map(p => path.normalize(p))
    .filter(p => p && !seen.has(p) && seen.add(p))
    .join(path.delimiter);
}

export function detectTexLive(extraPaths?: string[]): TexLiveDetection {
  const searchPath = buildSearchPath(extraPaths);
  const commands: Record<string, { path: string | null; version: string | null }> = {};

  for (const tool of ALL_TOOLS) {
    const toolPath = which(tool, searchPath);
    commands[tool] = { path: toolPath, version: toolPath ? `${tool} found` : null };
  }

  // Get kpsewhich TEXMFROOT
  let texmfroot: string | null = null;
  if (commands.kpsewhich.path) {
    execTool([commands.kpsewhich.path, "-var-value=TEXMFROOT"], searchPath).then(({ code, stdout }) => {
      if (code === 0 && stdout) texmfroot = stdout.split("\n").pop()?.trim() ?? null;
    });
  }

  const missingRequired = REQUIRED_TOOLS.filter(t => commands[t].path === null);
  const missingRecommended = RECOMMENDED_TOOLS.filter(t => commands[t].path === null);

  const detectedPaths = Object.values(commands).map(c => c.path).filter(Boolean) as string[];
  let activeBinDir: string | null = null;
  for (const pref of ["pdflatex", "kpsewhich", "xelatex", "lualatex", "biber", "latexmk"] as const) {
    if (commands[pref].path) { activeBinDir = path.dirname(commands[pref].path!); break; }
  }

  let status: TexLiveDetection["status"];
  let reason: string;
  if (detectedPaths.length === 0) {
    status = "missing";
    reason = "No TeX Live or MacTeX tools found on PATH or known locations.";
  } else if (missingRequired.length > 0) {
    status = "existing-partial";
    reason = "TeX installation detected but required tools missing.";
  } else {
    status = "existing-usable";
    reason = "Required TeX tools are available.";
  }

  const knownTexBinDirs = discoverKnownBinDirs();

  return {
    status,
    reason,
    activeBinDir,
    texmfroot,
    commands: commands as TexLiveCommands,
    missingRequired,
    missingRecommended,
    knownTexBinDirs,
    searchPath,
  };
}

export function detectTectonic(): TectonicDetection {
  const searchPath = buildSearchPath();
  const tectonicBin = process.platform === "win32" ? "tectonic.exe" : "tectonic";

  // Check PATH
  const fromPath = which(tectonicBin, searchPath);
  if (fromPath) {
    return {
      status: "available",
      reason: "Tectonic found on PATH.",
      path: fromPath,
      source: "path",
      version: null, // could add version detection
    };
  }

  return {
    status: "missing",
    reason: "No Tectonic executable found on PATH or bundled locations.",
    path: null,
    source: null,
    version: null,
  };
}
```

