### 2. texlive.ts
Port detection logic from detect_tectonic.py + detect_texlive.py:

```typescript
import { execFileSync } from "node:child_process";
import { existsSync } from "node:fs";
import { TectonicDetection, TexliveDetection, CommandInfo } from "./types";

const TECTONIC_BUNDLED = "/Users/shivam94/.codex/.tmp/bundled-marketplaces/openai-bundled/plugins/latex/bin/tectonic";
const TINYTEX_BIN = "/Users/shivam94/Documents/Resume/texlive/bin/universal-darwin";
const REQUIRED_TOOLS = ["latexmk", "pdflatex", "kpsewhich"] as const;
const RECOMMENDED_TOOLS = ["xelatex", "lualatex", "biber"] as const;
const ALL_TOOLS = [...REQUIRED_TOOLS, ...RECOMMENDED_TOOLS] as const;

export function detectTectonic(): TectonicDetection {
  // Check bundled first, then PATH
  if (existsSync(TECTONIC_BUNDLED)) {
    try {
      const out = execFileSync(TECTONIC_BUNDLED, ["--version"], { encoding: "utf-8", timeout: 5000 });
      const version = out.split("\n")[0]?.trim() || null;
      return { status: "available", path: TECTONIC_BUNDLED, version, source: "bundled" };
    } catch { /* fall through */ }
  }
  // Check PATH
  try {
    const which = execFileSync("which", ["tectonic"], { encoding: "utf-8", timeout: 3000 }).trim();
    if (which) {
      const out = execFileSync(which, ["--version"], { encoding: "utf-8", timeout: 5000 });
      const version = out.split("\n")[0]?.trim() || null;
      return { status: "available", path: which, version, source: "path" };
    }
  } catch { /* not found */ }
  return { status: "missing", path: null, version: null, source: null };
}

export function buildSearchPath(): string {
  const paths = [TINYTEX_BIN, "/Library/TeX/texbin"];
  const currentPath = process.env.PATH || "";
  return [...paths, ...currentPath.split(":").filter(Boolean)].join(":");
}

export function detectTexlive(): TexliveDetection {
  const searchPath = buildSearchPath();
  const commands: Record<string, CommandInfo> = {};

  for (const tool of ALL_TOOLS) {
    commands[tool] = { path: null, version: null };
    try {
      const which = execFileSync("which", [tool], { env: { PATH: searchPath }, encoding: "utf-8", timeout: 3000 }).trim();
      if (which) {
        commands[tool].path = which;
        try {
          const versionArgs = tool === "latexmk" ? ["-norc", "-v"] : ["--version"];
          const out = execFileSync(which, versionArgs, { env: { PATH: searchPath }, encoding: "utf-8", timeout: 5000 });
          commands[tool].version = out.split("\n")[0]?.trim() || null;
        } catch { /* version failed */ }
      }
    } catch { /* not found */ }
  }

  const missingRequired = REQUIRED_TOOLS.filter(t => !commands[t].path);
  const missingRecommended = RECOMMENDED_TOOLS.filter(t => !commands[t].path);
  const activeBinDir = commands.pdflatex.path || commands.kpsewhich.path 
    ? TINYTEX_BIN 
    : null;

  let status: TexliveDetection["status"];
  let reason: string;

  if (!commands.kpsewhich.path && !commands.pdflatex.path) {
    status = "missing";
    reason = "No TeX Live tools found";
  } else if (missingRequired.length > 0) {
    status = "existing-partial";
    reason = `Missing required tools: ${missingRequired.join(", ")}`;
  } else {
    status = "existing-usable";
    reason = "All required TeX tools available";
  }

  return { status, reason, activeBinDir, commands, searchPath };
}
```

