import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";
import { compileLatex, checkTectonicSuitability } from "./compile";
import { runDoctor } from "./doctor";

function formatCompileResult(r: any): string {
  if (r.success) return `✅ Compiled: ${r.pdfPath}`;
  return `❌ Compilation failed. ${r.attempts.map((a: any) => a.skipped ? `  - ${a.compiler}: skipped (${a.reason})` : `  - ${a.compiler}: exit ${a.exitCode}, pdf ${a.pdfExists ? "found" : "not found"}`).join("\n")}`;
}

function formatDoctorResult(r: any): string {
  const lines = [`Overall: ${r.ready ? "✅ Ready" : "❌ Not ready"}`];
  lines.push(`\nTectonic: ${r.tectonic.detection.status}${r.tectonic.detection.path ? ` (${r.tectonic.detection.path})` : ""}`);
  lines.push(`  Smoke test: ${r.tectonic.smokeTest.passed ? "✅ passed" : r.tectonic.smokeTest.attempted ? "❌ failed" : "⏭️ skipped"}`);
  lines.push(`\nTeX Live: ${r.texlive.detection.status}${r.texlive.detection.activeBinDir ? ` (${r.texlive.detection.activeBinDir})` : ""}`);
  if (r.texlive.detection.commands.pdflatex?.path) lines.push(`  pdflatex: ${r.texlive.detection.commands.pdflatex.path}`);
  if (r.texlive.detection.commands.latexmk?.path) lines.push(`  latexmk: ${r.texlive.detection.commands.latexmk.path}`);
  lines.push(`  Smoke test: ${r.texlive.smokeTest.passed ? "✅ passed" : r.texlive.smokeTest.attempted ? "❌ failed" : "⏭️ skipped"}`);
  return lines.join("\n");
}

export default function (pi: ExtensionAPI): void {
  // latex-compile
  pi.registerTool({
    name: "latex-compile",
    label: "LaTeX Compile",
    description: "Compile a .tex file to PDF using local TeX Live or Tectonic",
    promptSnippet: "latex-compile: Compile .tex files to PDF",
    promptGuidelines: [
      "Use latex-compile to compile .tex → PDF",
      "Auto-mode tries TeX Live first, falls back to Tectonic",
      "Two-pass pdflatex for cross-references",
    ],
    parameters: Type.Object({
      tex_file: Type.String({ description: "Path to the .tex file to compile" }),
      compiler: Type.Optional(Type.Union([
        Type.Literal("auto"), Type.Literal("tectonic"), Type.Literal("texlive"),
      ], { description: "Compiler selection. auto: prefer TeX Live, fallback Tectonic" })),
      engine: Type.Optional(Type.Union([
        Type.Literal("pdflatex"), Type.Literal("xelatex"), Type.Literal("lualatex"),
      ], { description: "TeX engine. Default: pdflatex" })),
      output_directory: Type.Optional(Type.String({ description: "Output directory for PDF" })),
    }),
    async execute(_id, params, _signal, _onUpdate, _ctx) {
      const result = compileLatex(params.tex_file, {
        compiler: params.compiler as any,
        engine: params.engine as any,
        outputDirectory: params.output_directory,
      });
      return { content: [{ type: "text", text: formatCompileResult(result) }], details: result };
    },
  });

  // latex-doctor
  pi.registerTool({
    name: "latex-doctor",
    label: "LaTeX Doctor",
    description: "Check if LaTeX engines are installed and working. Runs a smoke test compile.",
    promptSnippet: "latex-doctor: Diagnose LaTeX installation",
    parameters: Type.Object({
      json: Type.Optional(Type.Boolean({ description: "Return structured JSON output" })),
    }),
    async execute(_id, params, _signal, _onUpdate, _ctx) {
      const result = runDoctor();
      return {
        content: [{ type: "text", text: params.json ? JSON.stringify(result, null, 2) : formatDoctorResult(result) }],
        details: result,
      };
    },
  });

  // latex-tectonic-suitability
  pi.registerTool({
    name: "latex-tectonic-suitability",
    label: "Tectonic Suitability",
    description: "Check if a LaTeX project is compatible with Tectonic compiler",
    promptSnippet: "latex-tectonic-suitability: Check Tectonic compatibility",
    parameters: Type.Object({
      tex_file: Type.String({ description: "Path to the .tex file to analyze" }),
    }),
    async execute(_id, params, _signal, _onUpdate, _ctx) {
      const result = checkTectonicSuitability(params.tex_file);
      const text = result.suitable
        ? `✅ Project is suitable for Tectonic`
        : `❌ Project is NOT suitable for Tectonic:\n${result.reasons.map(r => `  - ${r}`).join("\n")}`;
      return { content: [{ type: "text", text }], details: result };
    },
  });
}
